import{_ as a,o as t,c as o,ag as l}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse(`{"title":"claude-code-agent-os","description":"","frontmatter":{"title":"claude-code-agent-os","concept":"代理能力扩展库架构","concept_id":"claude-code-agent-os","aliases":["Everything Claude Code","Agent OS"],"sources":["02_Library/Claude_Code_Skills/[Claude_Code_Skills] Google engineer automated 80% of his work with Claude Code. here's the exact system he built..md"],"related_concepts":["[[claude-code-mastery]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/claude-code-agent-os.md","filePath":"wiki/concepts/claude-code-agent-os.md","lastUpdated":null}`),d={name:"wiki/concepts/claude-code-agent-os.md"};function s(i,e,r,c,n,u){return t(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="代理能力扩展库架构-claude-code-agent-os" tabindex="-1">代理能力扩展库架构 (Claude Code Agent OS) <a class="header-anchor" href="#代理能力扩展库架构-claude-code-agent-os" aria-label="Permalink to &quot;代理能力扩展库架构 (Claude Code Agent OS)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在 Claude Code 等 CLI 工具外壳之上，通过引入一组专门规划的“角色定义插件”和“技能动作集”构成一整套类似操作系统的应用生态。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>能力高度模块化</strong>：诸如 TDD、代码 Review、架构设计分别有专有的 <code>.md</code> 引导和相应的终端技能集成。（来源：<a href="/s/webclips/library/Claude_Code_Skills/Claude_Code_Skills - Google engineer automated 80percent of his work with Claude Code. here&#39;s the exact system he built..html">[Claude_Code_Skills] Google engineer automated 80% of his work with Claude Code. here&#39;s the exact system he built..md</a>）</li><li><strong>按需加载防撑爆</strong>：这种架构需要极度关注上下文耗损（如 20k Token bug 的膨胀危机），绝不能一次性导入全部插件，必须根据当前上下文精确抽取。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>当需要构建完全自动化的工作流（如接收代码请求、拉取分支、测试合并的流水线）时，利用模块化的套件库比完全从头给 AI 手打 Prompt 有数百倍的效率提升。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/claude-code-mastery.html">claude-code-mastery</a> — 高阶环境配置技巧。</li></ul>',9)])])}const m=a(d,[["render",s]]);export{_ as __pageData,m as default};
